  resolveMerchGroupValue,
  RFQ_LIST_ITEM_EXCLUDE_ATTRIBUTES,
} = require('../../helpers/rfqListQuery');

describe('rfqListQuery', () => {
  it('buildMerchGroupMap indexes merch groups by mg_id', () => {
    const map = buildMerchGroupMap([
      { dataValues: { mg_id: 10, mg_code: 'A', mg_desc: 'Alpha' } },
      { dataValues: { mg_id: 20, mg_code: 'B', mg_desc: 'Beta' } },
    ]);
    expect(map.get('10').mg_desc).toBe('Alpha');
    expect(map.get('20').mg_code).toBe('B');
  });

  it('resolveMerchGroupValue does not embed the full merchGroup catalog', () => {
